import React, { createContext, useContext, useMemo, ReactNode } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { apiRequest, getQueryFn, queryClient } from "@/lib/query-client";

interface AuthUser {
  id: string;
  username: string;
}

interface AuthContextValue {
  user: AuthUser | null;
  isLoading: boolean;
  login: (username: string, password: string) => Promise<void>;
  register: (username: string, password: string) => Promise<void>;
  logout: () => Promise<void>;
  loginError: string | null;
  registerError: string | null;
  isLoggingIn: boolean;
  isRegistering: boolean;
}

const AuthContext = createContext<AuthContextValue | null>(null);

export function AuthProvider({ children }: { children: ReactNode }) {
  const userQuery = useQuery<AuthUser | null>({
    queryKey: ["/api/user"],
    queryFn: getQueryFn({ on401: "returnNull" }),
    staleTime: Infinity,
    retry: false,
  });

  const loginMutation = useMutation({
    mutationFn: async ({ username, password }: { username: string; password: string }) => {
      const res = await apiRequest("POST", "/api/login", { username, password });
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/user"] });
    },
  });

  const registerMutation = useMutation({
    mutationFn: async ({ username, password }: { username: string; password: string }) => {
      const res = await apiRequest("POST", "/api/register", { username, password });
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/user"] });
    },
  });

  const logoutMutation = useMutation({
    mutationFn: async () => {
      await apiRequest("POST", "/api/logout");
    },
    onSuccess: () => {
      queryClient.setQueryData(["/api/user"], null);
      queryClient.invalidateQueries();
    },
  });

  const login = async (username: string, password: string) => {
    loginMutation.reset();
    await loginMutation.mutateAsync({ username, password });
  };

  const register = async (username: string, password: string) => {
    registerMutation.reset();
    await registerMutation.mutateAsync({ username, password });
  };

  const logout = async () => {
    await logoutMutation.mutateAsync();
  };

  const loginError = loginMutation.error
    ? (loginMutation.error as any)?.message?.includes("401")
      ? "Invalid username or password"
      : "Login failed. Please try again."
    : null;

  const registerError = registerMutation.error
    ? (registerMutation.error as any)?.message?.includes("409")
      ? "Username already taken"
      : (registerMutation.error as any)?.message?.includes("400")
      ? "Username (3+ chars) and password (6+ chars) required"
      : "Registration failed. Please try again."
    : null;

  const value = useMemo(
    () => ({
      user: userQuery.data ?? null,
      isLoading: userQuery.isLoading,
      login,
      register,
      logout,
      loginError,
      registerError,
      isLoggingIn: loginMutation.isPending,
      isRegistering: registerMutation.isPending,
    }),
    [
      userQuery.data,
      userQuery.isLoading,
      loginMutation.isPending,
      loginMutation.error,
      registerMutation.isPending,
      registerMutation.error,
      logoutMutation.isPending,
    ]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error("useAuth must be used within an AuthProvider");
  }
  return context;
}

import { BigQuery } from "@google-cloud/bigquery";
import * as fs from "fs";
import * as os from "os";
import * as path from "path";

let bqClient: BigQuery | null = null;
let tempKeyFile: string | null = null;

function getProjectId(): string {
  const projectId = process.env.GCP_PROJECT_ID;
  if (!projectId) throw new Error("GCP_PROJECT_ID environment variable is required");
  return projectId;
}

function getDatasetId(): string {
  return process.env.BQ_DATASET || "medicaid_data";
}

function getViewId(): string {
  return `${getProjectId()}.${getDatasetId()}.medicaid_claims_view`;
}

function getRawTableId(): string {
  return `${getProjectId()}.${getDatasetId()}.medicaid_provider_spending`;
}

export function getBigQueryClient(): BigQuery {
  if (bqClient) return bqClient;

  const raw = process.env.GCP_SERVICE_ACCOUNT_JSON;
  if (!raw) throw new Error("GCP_SERVICE_ACCOUNT_JSON environment variable is required");

  if (raw.trim().startsWith("{")) {
    tempKeyFile = path.join(os.tmpdir(), `gcp_sa_${Date.now()}.json`);
    fs.writeFileSync(tempKeyFile, raw);
    bqClient = new BigQuery({
      projectId: getProjectId(),
      keyFilename: tempKeyFile,
    });
  } else {
    bqClient = new BigQuery({
      projectId: getProjectId(),
      keyFilename: raw,
    });
  }

  return bqClient;
}

async function query<T = Record<string, unknown>>(sql: string, params?: Record<string, unknown>): Promise<T[]> {
  const client = getBigQueryClient();
  const options: { query: string; params?: Record<string, unknown> } = { query: sql };
  if (params) options.params = params;
  const [rows] = await client.query(options);
  return rows as T[];
}

export interface ProviderSummary {
